def fetchone_dict(cur: sqlite3.Cursor) -> Optional[Dict[str, Any]]:
    row = cur.fetchone()
    return dict(row) if row else None


def fetchall_dict(cur: sqlite3.Cursor) -> List[Dict[str, Any]]:
    rows = cur.fetchall()
    return [dict(r) for r in rows]


def compute_majority_vote(labels: List[str]) -> Tuple[str, int]:
    counts: Dict[str, int] = {}
    for l in labels:
        counts[l] = counts.get(l, 0) + 1
    max_count = max(counts.values())
    winners = sorted([k for k, v in counts.items() if v == max_count])
    return winners[0], max_count


def update_aggregation(conn: sqlite3.Connection, task_id: str):
    cur = conn.cursor()
    cur.execute("SELECT label FROM annotations WHERE task_id = ?", (task_id,))
    labels = [r["label"] for r in cur.fetchall()]
    if not labels:
        cur.execute("DELETE FROM aggregated_labels WHERE task_id = ?", (task_id,))
        return
    maj_label, vote_count = compute_majority_vote(labels)
    total = len(labels)
    now = utcnow_iso()
    cur.execute("""
    INSERT INTO aggregated_labels(task_id, label, vote_count, total_annotations, updated_at)
    VALUES(?, ?, ?, ?, ?)
    ON CONFLICT(task_id) DO UPDATE SET
        label=excluded.label,
        vote_count=excluded.vote_count,
        total_annotations=excluded.total_annotations,
        updated_at=excluded.updated_at
    """, (task_id, maj_label, vote_count, total, now))


