def ensure_label_in_set(conn: sqlite3.Connection, label_set_id: str, label: str):
    cur = conn.cursor()
    cur.execute("SELECT class_names_json FROM label_sets WHERE label_set_id = ?", (label_set_id,))
    row = cur.fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="Label set not found")
    classes = json.loads(row["class_names_json"])
    if label not in classes:
        raise HTTPException(status_code=400, detail="Label not in label set classes")


def resolve_device(device: str) -> torch.device:
    if device == "auto":
        return torch.device("cuda" if torch.cuda.is_available() else "cpu")
    if device == "cuda":
        if not torch.cuda.is_available():
            raise HTTPException(status_code=400, detail="CUDA not available")
        return torch.device("cuda")
    if device == "cpu":
        return torch.device("cpu")
    raise HTTPException(status_code=400, detail="Invalid device; use auto|cpu|cuda")


