@app.get("/label_sets/{label_set_id}/dataset")
def export_dataset(label_set_id: str, min_total_annotations: int = 1, require_majority: bool = False, majority_ratio: float = 0.5):
    min_total_annotations = max(1, int(min_total_annotations))
    majority_ratio = float(majority_ratio)
    if not (0.0 < majority_ratio <= 1.0):
        raise HTTPException(status_code=400, detail="majority_ratio must be in (0, 1]")
    with DB_LOCK:
        conn = get_db()
        cur = conn.cursor()
        cur.execute("SELECT class_names_json FROM label_sets WHERE label_set_id = ?", (label_set_id,))
        ls = cur.fetchone()
        if not ls:
            conn.close()
            raise HTTPException(status_code=404, detail="Label set not found")
        classes = json.loads(ls["class_names_json"])
        cur.execute("""
        SELECT t.task_id, t.image_id, i.file_path, a.label, a.vote_count, a.total_annotations, a.updated_at
        FROM tasks t
        JOIN images i ON i.image_id = t.image_id
        JOIN aggregated_labels a ON a.task_id = t.task_id
        WHERE t.label_set_id = ?
          AND a.total_annotations >= ?
        """, (label_set_id, min_total_annotations))
        rows = fetchall_dict(cur)
        conn.close()
    if require_majority:
        filtered = []
        for r in rows:
            if r["vote_count"] / max(1, r["total_annotations"]) >= majority_ratio:
                filtered.append(r)
        rows = filtered
    return {"label_set_id": label_set_id, "class_names": classes, "items": rows, "count": len(rows)}


class ImageLabelDataset(Dataset):
    def __init__(self, items: List[Dict[str, Any]], class_to_idx: Dict[str, int], image_size: int):
        self.items = items
        self.class_to_idx = class_to_idx
        self.image_size = image_size

    def __len__(self):
        return len(self.items)

    def _load_image(self, path: str) -> torch.Tensor:
        img = Image.open(path).convert("RGB").resize((self.image_size, self.image_size))
        arr = np.asarray(img, dtype=np.float32) / 255.0
        arr = np.transpose(arr, (2, 0, 1))
        return torch.from_numpy(arr)

    def __getitem__(self, idx: int):
        r = self.items[idx]
        x = self._load_image(r["file_path"])
        y = self.class_to_idx[r["label"]]
        return x, y


class SimpleCNN(nn.Module):
    def __init__(self, num_classes: int):
        super().__init__()
        self.conv1 = nn.Conv2d(3, 32, 3, padding=1)
        self.conv2 = nn.Conv2d(32, 64, 3, padding=1)
        self.conv3 = nn.Conv2d(64, 128, 3, padding=1)
        self.pool = nn.MaxPool2d(2, 2)
        self.gap = nn.AdaptiveAvgPool2d((1, 1))
        self.fc = nn.Linear(128, num_classes)

    def forward(self, x):
        x = self.pool(F.relu(self.conv1(x)))
        x = self.pool(F.relu(self.conv2(x)))
        x = self.pool(F.relu(self.conv3(x)))
        x = self.gap(x).flatten(1)
        return self.fc(x)


def train_model_on_label_set(
    label_set_id: str,
    image_size: int,
    epochs: int,
    batch_size: int,
    lr: float,
    min_total_annotations: int,
    require_majority: bool,
    majority_ratio: float,
    device: torch.device
) -> Dict[str, Any]:
    with DB_LOCK:
        conn = get_db()
        cur = conn.cursor()
        cur.execute("SELECT class_names_json FROM label_sets WHERE label_set_id = ?", (label_set_id,))
        ls = cur.fetchone()
        if not ls:
            conn.close()
            raise HTTPException(status_code=404, detail="Label set not found")
        class_names = json.loads(ls["class_names_json"])
        cur.execute("""
        SELECT t.task_id, i.file_path, a.label, a.vote_count, a.total_annotations
        FROM tasks t
        JOIN images i ON i.image_id = t.image_id
        JOIN aggregated_labels a ON a.task_id = t.task_id
        WHERE t.label_set_id = ?
          AND a.total_annotations >= ?
        """, (label_set_id, min_total_annotations))
        items = fetchall_dict(cur)
        cur.execute("""
        SELECT COUNT(*) as n FROM annotations an
        JOIN tasks t ON t.task_id = an.task_id
        WHERE t.label_set_id = ?
        """, (label_set_id,))
        n_annotations = int(cur.fetchone()["n"])
        conn.close()

    if require_majority:
        items = [r for r in items if (r["vote_count"] / max(1, r["total_annotations"])) >= majority_ratio]

    if not items:
        raise HTTPException(status_code=400, detail="No aggregated labeled items available for training with given filters")

    class_to_idx = {c: i for i, c in enumerate(class_names)}
    for r in items:
        if r["label"] not in class_to_idx:
            raise HTTPException(status_code=400, detail=f"Found label not in class_names: {r['label']}")

    ds = ImageLabelDataset(items, class_to_idx, image_size)
    dl = DataLoader(ds, batch_size=batch_size, shuffle=True, num_workers=0)

    model = SimpleCNN(num_classes=len(class_names)).to(device)
    opt = torch.optim.Adam(model.parameters(), lr=lr)
    loss_fn = nn.CrossEntropyLoss()

    model.train()
    steps = 0
    running_loss = 0.0
    for ep in range(epochs):
        for xb, yb in dl:
            xb = xb.to(device)
            yb = yb.to(device)
            opt.zero_grad(set_to_none=True)
            logits = model(xb)
            loss = loss_fn(logits, yb)
            loss.backward()
            opt.step()
            steps += 1
            running_loss += float(loss.detach().cpu().item())

    avg_loss = running_loss / max(1, steps)

    model_id = str(uuid.uuid4())
    artifact_path = os.path.join(MODEL_DIR, f"{model_id}.pt")
    payload = {
        "model_id": model_id,
        "label_set_id": label_set_id,
        "class_names": class_names,
        "image_size": image_size,
        "state_dict": model.state_dict(),
    }
    torch.save(payload, artifact_path)

    now = utcnow_iso()
    with DB_LOCK:
        conn = get_db()
        cur = conn.cursor()
        cur.execute("""
        INSERT INTO models(model_id, label_set_id, num_classes, class_names_json, image_size, epochs, batch_size, lr,
                           trained_on_tasks, trained_on_annotations, artifact_path, created_at)
        VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (model_id, label_set_id, len(class_names), json.dumps(class_names), image_size, epochs, batch_size, lr,
              len(items), n_annotations, artifact_path, now))
        conn.commit()
        conn.close()

    return {
        "model_id": model_id,
        "label_set_id": label_set_id,
        "num_classes": len(class_names),
        "class_names": class_names,
        "image_size": image_size,
        "epochs": epochs,
        "batch_size": batch_size,
        "lr": lr,
        "device": str(device),
        "trained_on_tasks": len(items),
        "trained_on_annotations": n_annotations,
        "artifact_path": artifact_path,
        "avg_train_loss": avg_loss,
        "created_at": now,
    }


@app.post("/train")
def train(req: TrainRequest):
    device = resolve_device(req.device)
    result = train_model_on_label_set(
        label_set_id=req.label_set_id,
        image_size=req.image_size,
        epochs=req.epochs,
        batch_size=req.batch_size,
        lr=req.lr,
        min_total_annotations=req.min_total_annotations,
        require_majority=req.require_majority,
        majority_ratio=req.majority_ratio,
        device=device,
    )
    return result


@app.get("/models")
def list_models(label_set_id: Optional[str] = None, limit: int = 50, offset: int = 0):
    limit = max(1, min(500, int(limit)))
    offset = max(0, int(offset))
    with DB_LOCK:
        conn = get_db()
        cur = conn.cursor()
        if label_set_id:
            cur.execute("""
            SELECT model_id, label_set_id, num_classes, class_names_json, image_size, epochs, batch_size, lr,
                   trained_on_tasks, trained_on_annotations, artifact_path, created_at
            FROM models
            WHERE label_set_id = ?
            ORDER BY created_at DESC
            LIMIT ? OFFSET ?
            """, (label_set_id, limit, offset))
        else:
            cur.execute("""
            SELECT model_id, label_set_id, num_classes, class_names_json, image_size, epochs, batch_size, lr,
                   trained_on_tasks, trained_on_annotations, artifact_path, created_at
            FROM models
            ORDER BY created_at DESC
            LIMIT ? OFFSET ?
            """, (limit, offset))
        rows = fetchall_dict(cur)
        conn.close()
    for r in rows:
        r["class_names"] = json.loads(r.pop("class_names_json"))
    return {"models": rows, "limit": limit, "offset": offset}


@app.get("/models/{model_id}")
def get_model(model_id: str):
    with DB_LOCK:
        conn = get_db()
        cur = conn.cursor()
        cur.execute("""
        SELECT model_id, label_set_id, num_classes, class_names_json, image_size, epochs, batch_size, lr,
               trained_on_tasks, trained_on_annotations, artifact_path, created_at
        FROM models
        WHERE model_id = ?
        """, (model_id,))
        row = fetchone_dict(cur)
        conn.close()
    if not row:
        raise HTTPException(status_code=404, detail="Model not found")
    row["class_names"] = json.loads(row.pop("class_names_json"))
    return row


class PredictRequest(BaseModel):
    model_id: str
    image_b64: str


@app.post("/predict")
def predict(req: PredictRequest):
    with DB_LOCK:
        conn = get_db()
        cur = conn.cursor()
        cur.execute("SELECT artifact_path FROM models WHERE model_id = ?", (req.model_id,))
        row = cur.fetchone()
        conn.close()
    if not row:
        raise HTTPException(status_code=404, detail="Model not found")
    artifact_path = row["artifact_path"]
    if not os.path.exists(artifact_path):
        raise HTTPException(status_code=500, detail="Model artifact missing")

    try:
        img_bytes = base64.b64decode(req.image_b64, validate=True)
        img = Image.open(io.BytesIO(img_bytes)).convert("RGB")
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image_b64")

    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    payload = torch.load(artifact_path, map_location=device)
    class_names = payload["class_names"]
    image_size = int(payload["image_size"])
    state_dict = payload["state_dict"]

    model = SimpleCNN(num_classes=len(class_names)).to(device)
    model.load_state_dict(state_dict)
    model.eval()

    img = img.resize((image_size, image_size))
    arr = np.asarray(img, dtype=np.float32) / 255.0
    arr = np.transpose(arr, (2, 0, 1))
    xb = torch.from_numpy(arr).unsqueeze(0).to(device)

    with torch.no_grad():
        logits = model(xb)
        probs = torch.softmax(logits, dim=1).detach().cpu().numpy()[0]
    idx = int(np.argmax(probs))
    return {"predicted_label": class_names[idx], "probs": {class_names[i]: float(probs[i]) for i in range(len(class_names))}}


